// Extract partner_id from query
const query = $input.first().json.query;
const partner_id = query.partner_id;

if (!partner_id) {
  throw new Error('partner_id is required');
}

return { json: { partner_id } };

// Format dashboard data
const partnerInfo = $input.all()[1].json[0];
const clientsN1 = $input.all()[2].json;
const clientsN2 = $input.all()[3].json;
const commissions = $input.all()[4].json;

const nombreClientsN1 = clientsN1.length;
const nombreClientsN2 = clientsN2.length;

const revenueN1Mensuel = clientsN1.reduce((sum, client) => {
  return sum + (client.montant_mensuel || 0);
}, 0) * (partnerInfo.commission_taux_niveau1 / 100);

const revenueN2Mensuel = clientsN2.reduce((sum, client) => {
  return sum + (client.montant_mensuel || 0);
}, 0) * (partnerInfo.commission_taux_niveau2 / 100);

const totalCommissionsEnAttente = commissions
  .filter(c => c.statut === 'en_attente')
  .reduce((sum, c) => sum + c.total, 0);

const totalCommissionsPaye = commissions
  .filter(c => c.statut === 'paye')
  .reduce((sum, c) => sum + c.total, 0);

const historiqueCommissions = commissions.map(c => ({
  mois: c.mois,
  statut: c.statut,
  montant: c.total
}));

const dashboard = {
  partner: partnerInfo,
  nombre_clients_n1: nombreClientsN1,
  nombre_clients_n2: nombreClientsN2,
  revenue_n1_mensuel: Math.round(revenueN1Mensuel * 100) / 100,
  revenue_n2_mensuel: Math.round(revenueN2Mensuel * 100) / 100,
  total_commissions_en_attente: totalCommissionsEnAttente,
  total_commissions_payees: totalCommissionsPaye,
  historique_commissions: historiqueCommissions
};

return { json: dashboard };
